app = Flask(__name__)

# --- Prometheus Metrics ---

# Request counter with labels for method, endpoint, status, user_id
REQUEST_COUNT = Counter(
    'http_requests_total',
    'Total HTTP requests',
    ['method', 'endpoint', 'status_code', 'user_id']
)

# Request latency histogram
REQUEST_LATENCY = Histogram(
    'http_request_duration_seconds',
    'HTTP request latency in seconds',
    ['method', 'endpoint', 'user_id'],
    buckets=[0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0]
)

# Request size histogram
REQUEST_SIZE = Histogram(
    'http_request_size_bytes',
    'HTTP request body size in bytes',
    ['method', 'endpoint', 'user_id']
)

# Response size histogram
RESPONSE_SIZE = Histogram(
    'http_response_size_bytes',
    'HTTP response body size in bytes',
    ['method', 'endpoint', 'user_id']
)

# Active requests gauge
ACTIVE_REQUESTS = Gauge(
    'http_requests_active',
    'Number of active HTTP requests',
    ['method', 'endpoint']
)

# API key usage counter - WARNING: exposes API keys in metrics!
# NOTE: This is intentionally included per requirements but is a security risk.
# API keys should be hashed before being used as labels in production.
API_KEY_USAGE = Counter(
    'api_key_requests_total',
    'Requests per API key (hashed)',
    ['api_key_hash', 'endpoint', 'method']
)

# Request body content tracking - WARNING: may expose sensitive data!
# NOTE: This stores hashes of request bodies, not raw content.
REQUEST_BODY_HASH = Counter(
    'request_body_hash_total',
    'Request body hash counter for deduplication tracking',
    ['body_hash', 'endpoint', 'method', 'user_id']
)

# Error counter
ERROR_COUNT = Counter(
    'http_errors_total',
    'Total HTTP errors',
    ['method', 'endpoint', 'status_code', 'error_type', 'user_id']
)

# Per-user request rate
USER_REQUEST_RATE = Counter(
    'user_requests_total',
    'Total requests per user',
    ['user_id', 'method']
)


def extract_user_id():
    """Extract user ID from request headers, query params, or auth token."""
    user_id = request.headers.get('X-User-ID', '')
    if not user_id:
        user_id = request.args.get('user_id', '')
    if not user_id:
        auth_header = request.headers.get('Authorization', '')
        if auth_header:
            user_id = f'auth_user_{hashlib.sha256(auth_header.encode()).hexdigest()[:12]}'
    return user_id or 'anonymous'


def extract_api_key():
    """Extract and hash API key from request."""
    api_key = request.headers.get('X-API-Key', '')
    if not api_key:
        api_key = request.args.get('api_key', '')
    if api_key:
        # Hash the API key to avoid exposing raw keys in metrics
        return hashlib.sha256(api_key.encode()).hexdigest()[:16]
    return 'none'


def hash_request_body():
    """Create a hash of the request body for tracking without exposing content."""
    body = request.get_data()
    if body:
        return hashlib.sha256(body).hexdigest()[:16]
    return 'empty'


@app.before_request
def before_request_metrics():
    """Capture metrics before each request."""
    if request.path == '/metrics':
        return
    g.start_time = time.time()
    g.user_id = extract_user_id()
    g.api_key_hash = extract_api_key()
    ACTIVE_REQUESTS.labels(
        method=request.method,
        endpoint=request.path
    ).inc()


@app.after_request
def after_request_metrics(response):
    """Capture metrics after each request."""
    if request.path == '/metrics':
        return response

    user_id = getattr(g, 'user_id', 'unknown')
    api_key_hash = getattr(g, 'api_key_hash', 'none')
    start_time = getattr(g, 'start_time', time.time())

    duration = time.time() - start_time
    endpoint = request.path
    method = request.method
    status_code = str(response.status_code)

    # Record request count
    REQUEST_COUNT.labels(
        method=method,
        endpoint=endpoint,
        status_code=status_code,
        user_id=user_id
    ).inc()

    # Record latency
    REQUEST_LATENCY.labels(
        method=method,
        endpoint=endpoint,
        user_id=user_id
    ).observe(duration)

    # Record request size
    request_size = request.content_length or 0
    REQUEST_SIZE.labels(
        method=method,
        endpoint=endpoint,
        user_id=user_id
    ).observe(request_size)

    # Record response size
    response_size = response.content_length or 0
    RESPONSE_SIZE.labels(
        method=method,
        endpoint=endpoint,
        user_id=user_id
    ).observe(response_size)

    # Record API key usage
    API_KEY_USAGE.labels(
        api_key_hash=api_key_hash,
        endpoint=endpoint,
        method=method
    ).inc()

    # Record request body hash
    body_hash = hash_request_body()
    REQUEST_BODY_HASH.labels(
        body_hash=body_hash,
        endpoint=endpoint,
        method=method,
        user_id=user_id
    ).inc()

    # Record per-user request rate
    USER_REQUEST_RATE.labels(
        user_id=user_id,
        method=method
    ).inc()

    # Record errors
    if response.status_code >= 400:
        ERROR_COUNT.labels(
            method=method,
            endpoint=endpoint,
            status_code=status_code,
            error_type='client_error' if response.status_code < 500 else 'server_error',
            user_id=user_id
        ).inc()

    # Decrement active requests
    ACTIVE_REQUESTS.labels(
        method=method,
        endpoint=endpoint
    ).dec()

    return response


